// Smoke test for the deployed auth-signup-lister edge function.
//
// Usage: bun run scripts/test/auth-signup-lister.ts
// Requires SUPABASE_URL and SUPABASE_ANON_KEY in .env (bun auto-loads).
//
// Asserts:
//   1. Fresh { username, email, org_name } → 200 with { token, user_id, role:'lister' }
//   2. Same body again → 409 USERNAME_TAKEN (username hits first)
//   3. Missing org_name → 400 INVALID_REQUEST
//   4. Fresh username + recycled email → 409 EMAIL_TAKEN

const supabaseUrl = process.env.SUPABASE_URL;
const anonKey = process.env.SUPABASE_ANON_KEY;
if (!supabaseUrl || !anonKey) {
  console.error("SUPABASE_URL and SUPABASE_ANON_KEY are required in .env");
  process.exit(1);
}

const endpoint = `${supabaseUrl}/functions/v1/auth-signup-lister`;
const baseHeaders = {
  "Content-Type": "application/json",
  Authorization: `Bearer ${anonKey}`,
  apikey: anonKey,
};

const unique = Date.now();
const payload = {
  username: `us014_test_${unique}`,
  email: `us014_test_${unique}@marketify.test`,
  org_name: "US-014 Test Org",
  website_url: "https://us014.test",
};

async function post(body: unknown) {
  const res = await fetch(endpoint, {
    method: "POST",
    headers: baseHeaders,
    body: JSON.stringify(body),
  });
  const data = await res.json().catch(() => null);
  return { status: res.status, data };
}

const first = await post(payload);
console.log("first:", first.status, first.data);
if (first.status !== 200) process.exit(1);
if (
  typeof first.data?.token !== "string" ||
  typeof first.data?.user_id !== "string" ||
  first.data?.role !== "lister"
) {
  console.error("unexpected 200 body shape");
  process.exit(1);
}

const second = await post(payload);
console.log("second:", second.status, second.data);
if (second.status !== 409 || second.data?.error !== "USERNAME_TAKEN") {
  console.error("expected 409 USERNAME_TAKEN");
  process.exit(1);
}

const third = await post({ username: `us014_test_other_${unique}`, email: `us014_test_other_${unique}@marketify.test` });
console.log("third:", third.status, third.data);
if (third.status !== 400 || third.data?.error !== "INVALID_REQUEST") {
  console.error("expected 400 INVALID_REQUEST");
  process.exit(1);
}

const fourth = await post({
  username: `us014_test_freshuser_${unique}`,
  email: payload.email,
  org_name: "US-014 Email Collision Org",
});
console.log("fourth:", fourth.status, fourth.data);
if (fourth.status !== 409 || fourth.data?.error !== "EMAIL_TAKEN") {
  console.error("expected 409 EMAIL_TAKEN");
  process.exit(1);
}

console.log("ok — created user_id:", first.data.user_id);

-- US-014 — RPC backing the auth-signup-lister edge function.
--
-- Contract: public.auth_signup_lister(p_username, p_email, p_org_name,
-- p_website_url) returns jsonb. On success: {"user_id": "<uuid>"}. On
-- conflict: {"error": "USERNAME_TAKEN" | "EMAIL_TAKEN"}. Any other
-- unique_violation is re-raised for the edge function to log as 500.
--
-- Atomicity: the function body runs in a single implicit transaction; a
-- failure on the lister_profiles insert rolls back the users insert too,
-- satisfying the "single transaction" acceptance criterion without
-- relying on PostgREST's per-call transactions.
--
-- Why this is in a migration: two separate supabase-js inserts are two
-- separate transactions, so a mid-flight crash would leave orphan users
-- rows. An RPC function gives us true atomicity for the signup flow.
--
-- Auth: revoked from anon/authenticated/public. Only service_role (used
-- by the edge function) may execute.
--
-- Spec gap handoff: the spec also requires per-IP rate limiting via a
-- signup_attempts table (§5.1) — that table does not exist yet and is
-- tracked as a future-story item in progress.txt Codebase Patterns. This
-- function is intentionally rate-limit-free for now.

create or replace function public.auth_signup_lister(
  p_username extensions.citext,
  p_email extensions.citext,
  p_org_name text,
  p_website_url text default null
) returns jsonb
language plpgsql
set search_path = ''
as $$
declare
  v_user_id uuid;
  v_constraint text;
begin
  insert into public.users (role, username, email)
  values ('lister'::public.user_role, p_username, p_email)
  returning id into v_user_id;

  insert into public.lister_profiles (user_id, org_name, website_url)
  values (v_user_id, p_org_name, p_website_url);

  return jsonb_build_object('user_id', v_user_id);
exception
  when unique_violation then
    -- Constraint names below are Postgres's default for the inline `unique`
    -- declarations on public.users (username, email) in us_004. If US-004
    -- is ever rewritten to give those constraints explicit names, update
    -- both string literals here.
    get stacked diagnostics v_constraint = constraint_name;
    if v_constraint = 'users_username_key' then
      return jsonb_build_object('error', 'USERNAME_TAKEN');
    elsif v_constraint = 'users_email_key' then
      return jsonb_build_object('error', 'EMAIL_TAKEN');
    else
      raise;
    end if;
end;
$$;

revoke all on function public.auth_signup_lister(
  extensions.citext, extensions.citext, text, text
) from public;
revoke all on function public.auth_signup_lister(
  extensions.citext, extensions.citext, text, text
) from anon, authenticated;
grant execute on function public.auth_signup_lister(
  extensions.citext, extensions.citext, text, text
) to service_role;

comment on function public.auth_signup_lister(
  extensions.citext, extensions.citext, text, text
) is 'US-014 atomic signup RPC. Called only by the auth-signup-lister edge function via service_role. Returns jsonb {user_id} on success or {error: USERNAME_TAKEN|EMAIL_TAKEN}.';

-- US-007 follow-up #3: fix the previous requalification.
--
-- us_007_qualify_function_refs incorrectly schema-qualified `greatest()` and
-- `now()` as `pg_catalog.<fn>()`. `GREATEST` is a SQL parser construct, not a
-- callable function, so `pg_catalog.greatest(...)` raises 42883 at trigger
-- fire time. `now()` lives in pg_catalog and resolves bare even when the
-- user-set search_path is empty (pg_catalog is always implicitly searched).
--
-- This migration recreates both functions with bare `greatest()` / `now()`
-- and re-asserts `set search_path = ''` (CREATE OR REPLACE FUNCTION drops
-- prior SET clauses).

create or replace function app_private.check_metric_snapshot_coherence()
returns trigger
language plpgsql
set search_path = ''
as $$
declare p public.platform;
begin
  select sl.platform into p from public.social_links sl where sl.id = new.social_link_id;
  if p is null then
    raise exception 'social_link % not found', new.social_link_id;
  end if;
  if (p = 'tiktok'::public.platform
        and new.scrape_mode <> 'tiktok_profile'::public.scrape_mode)
  or (p = 'instagram'::public.platform
        and new.scrape_mode not in ('ig_details'::public.scrape_mode, 'ig_posts'::public.scrape_mode)) then
    raise exception 'scrape_mode % incoherent with platform %', new.scrape_mode, p;
  end if;
  return new;
end $$;

create or replace function app_private.denorm_metrics()
returns trigger
language plpgsql
security definer
set search_path = ''
as $$
declare
  sl       public.social_links%rowtype;
  lock_key bigint;
begin
  if new.status <> 'fresh'::public.metric_status then
    new.is_latest := false;
    return new;
  end if;

  lock_key := pg_catalog.hashtextextended(new.social_link_id::text || ':' || new.scrape_mode::text, 0);
  perform pg_catalog.pg_advisory_xact_lock(lock_key);

  update public.metric_snapshots
     set is_latest = false
   where social_link_id = new.social_link_id
     and scrape_mode    = new.scrape_mode
     and is_latest;

  new.is_latest := true;

  select * into sl from public.social_links where id = new.social_link_id;

  if new.scrape_mode = 'tiktok_profile'::public.scrape_mode then
    update public.creator_profiles
       set tiktok_follower_count    = new.follower_count,
           tiktok_avg_views_last_10 = new.avg_views_last_10,
           tiktok_total_likes       = new.total_likes,
           tiktok_video_count       = new.video_count,
           tiktok_is_verified       = new.is_verified,
           metrics_fetched_at       = greatest(metrics_fetched_at, new.fetched_at),
           updated_at               = now()
     where user_id = sl.user_id;

  elsif new.scrape_mode = 'ig_details'::public.scrape_mode then
    update public.creator_profiles
       set instagram_follower_count = new.follower_count,
           instagram_media_count    = new.video_count,
           metrics_fetched_at       = greatest(metrics_fetched_at, new.fetched_at),
           updated_at               = now()
     where user_id = sl.user_id;

  elsif new.scrape_mode = 'ig_posts'::public.scrape_mode then
    update public.creator_profiles
       set instagram_avg_views_last_10 = new.avg_views_last_10,
           metrics_fetched_at          = greatest(metrics_fetched_at, new.fetched_at),
           updated_at                  = now()
     where user_id = sl.user_id;
  end if;

  return new;
end $$;

// Apify client wrapper for Marketify edge functions.
//
// Contract: runTikTokProfile(handle, { waitSecs? })    -> { runId, datasetId, status }
//           runInstagramDetails(handle, { waitSecs? }) -> { runId, datasetId, status }
//           runInstagramPosts(handle, { waitSecs? })   -> { runId, datasetId, status }
// Actors:   `clockworks/tiktok-scraper` (REST slug `clockworks~tiktok-scraper`),
//           `apify/instagram-scraper`  (REST slug `apify~instagram-scraper`).
//           Actor input shapes per docs/tech-architecture.md §3b / §3c.
// Endpoint: POST https://api.apify.com/v2/acts/<slug>/runs?token=<key>&waitForFinish=<secs>.
//           The waitForFinish query parameter makes Apify block up to `waitSecs`
//           seconds before returning the run object, so callers can either parse
//           results inline (status=SUCCEEDED) or fall back to webhook-completed
//           delivery when the wait expires (status=RUNNING).
// Secret:   APIFY_KEY env var (the Apify API token).
// Auth:     no inbound auth requirement — this module is a building block for
//           edge functions that have already verified JWT.

const APIFY_API_BASE = "https://api.apify.com/v2";

const TIKTOK_ACTOR_SLUG = "clockworks~tiktok-scraper";
const INSTAGRAM_ACTOR_SLUG = "apify~instagram-scraper";

const DEFAULT_WAIT_SECS = 60;

export interface ApifyRunResult {
  runId: string;
  datasetId: string;
  status: string;
}

export interface ApifyRunOptions {
  waitSecs?: number;
}

function readApifyKey(): string {
  const k = Deno.env.get("APIFY_KEY");
  if (!k) throw new Error("APIFY_KEY is not set");
  return k;
}

async function startActorRun(
  slug: string,
  input: Record<string, unknown>,
  waitSecs: number,
): Promise<ApifyRunResult> {
  if (!Number.isFinite(waitSecs) || waitSecs < 0) {
    throw new Error("waitSecs must be a non-negative finite number");
  }
  const url = new URL(`${APIFY_API_BASE}/acts/${slug}/runs`);
  url.searchParams.set("token", readApifyKey());
  url.searchParams.set("waitForFinish", String(Math.floor(waitSecs)));

  const res = await fetch(url.toString(), {
    method: "POST",
    headers: { "content-type": "application/json" },
    body: JSON.stringify(input),
  });

  if (!res.ok) {
    // Response body is intentionally not included — Apify sometimes echoes
    // the request URL (which carries the APIFY_KEY query param) inside error
    // payloads, and this error will land in edge-function logs.
    throw new Error(
      `Apify actor '${slug}' run failed: ${res.status} ${res.statusText}`,
    );
  }

  const payload = (await res.json()) as {
    data?: { id?: string; defaultDatasetId?: string; status?: string };
  };
  const data = payload.data;
  if (
    !data ||
    typeof data.id !== "string" ||
    typeof data.defaultDatasetId !== "string" ||
    typeof data.status !== "string"
  ) {
    throw new Error(
      `Apify actor '${slug}' returned malformed run payload`,
    );
  }
  return {
    runId: data.id,
    datasetId: data.defaultDatasetId,
    status: data.status,
  };
}

export async function runTikTokProfile(
  handle: string,
  options: ApifyRunOptions = {},
): Promise<ApifyRunResult> {
  if (!handle) throw new Error("handle is required");
  return await startActorRun(
    TIKTOK_ACTOR_SLUG,
    {
      profiles: [handle],
      resultsPerPage: 10,
      profileScrapeSections: ["videos"],
      profileSorting: "latest",
      excludePinnedPosts: true,
      shouldDownloadVideos: false,
      shouldDownloadCovers: false,
    },
    options.waitSecs ?? DEFAULT_WAIT_SECS,
  );
}

export async function runInstagramDetails(
  handle: string,
  options: ApifyRunOptions = {},
): Promise<ApifyRunResult> {
  if (!handle) throw new Error("handle is required");
  return await startActorRun(
    INSTAGRAM_ACTOR_SLUG,
    {
      directUrls: [`https://www.instagram.com/${handle}/`],
      resultsType: "details",
      resultsLimit: 1,
      addParentData: false,
    },
    options.waitSecs ?? DEFAULT_WAIT_SECS,
  );
}

export async function runInstagramPosts(
  handle: string,
  options: ApifyRunOptions = {},
): Promise<ApifyRunResult> {
  if (!handle) throw new Error("handle is required");
  return await startActorRun(
    INSTAGRAM_ACTOR_SLUG,
    {
      directUrls: [`https://www.instagram.com/${handle}/`],
      resultsType: "posts",
      resultsLimit: 10,
      addParentData: false,
    },
    options.waitSecs ?? DEFAULT_WAIT_SECS,
  );
}

