// Live end-to-end for the apify-webhook SUCCEEDED branch (US-016).
//
// Usage: bun run scripts/test/apify-webhook-live.ts
// Requires APIFY_KEY, APIFY_WEBHOOK_SECRET, SUPABASE_URL, SUPABASE_ANON_KEY,
// SUPABASE_SERVICE_ROLE_KEY in .env.
//
// Hits a real Apify actor (spends a few cents) and therefore is not part of
// the default smoke suite. Verifies:
//   1. Apify tiktok_profile run reaches status SUCCEEDED within waitSecs
//   2. webhook POST with real dataset_id returns 200 inserted:true
//   3. metric_snapshots row exists with status='fresh' + derived metrics
//   4. creator_profiles denorm columns updated by the BEFORE INSERT trigger
//
// NB: writes to the seed social_link (11111111-...-020) and seed creator
// profile (user 11111111-...-002). Teardown is manual — the row stays in
// metric_snapshots for forensics.

import { createClient } from "@supabase/supabase-js";

const {
  APIFY_KEY,
  APIFY_WEBHOOK_SECRET,
  SUPABASE_URL,
  SUPABASE_ANON_KEY,
  SUPABASE_SERVICE_ROLE_KEY,
} = process.env;

if (
  !APIFY_KEY ||
  !APIFY_WEBHOOK_SECRET ||
  !SUPABASE_URL ||
  !SUPABASE_ANON_KEY ||
  !SUPABASE_SERVICE_ROLE_KEY
) {
  console.error(
    "APIFY_KEY, APIFY_WEBHOOK_SECRET, SUPABASE_URL, SUPABASE_ANON_KEY, SUPABASE_SERVICE_ROLE_KEY required",
  );
  process.exit(1);
}

const SEED_TIKTOK_SOCIAL_LINK_ID = "11111111-1111-1111-1111-111111111020";
const SEED_CREATOR_USER_ID = "11111111-1111-1111-1111-111111111002";
const TIKTOK_HANDLE = "tiktok"; // official TikTok account, cheap + stable
const endpoint = `${SUPABASE_URL}/functions/v1/apify-webhook`;

// 1. Kick off the Apify run (sync, waits up to 90s for finish).
console.log(`kicking Apify tiktok_profile for @${TIKTOK_HANDLE}...`);
const runUrl = new URL(
  "https://api.apify.com/v2/acts/clockworks~tiktok-scraper/runs",
);
runUrl.searchParams.set("token", APIFY_KEY);
runUrl.searchParams.set("waitForFinish", "90");

const runRes = await fetch(runUrl.toString(), {
  method: "POST",
  headers: { "content-type": "application/json" },
  body: JSON.stringify({
    profiles: [TIKTOK_HANDLE],
    resultsPerPage: 10,
    profileScrapeSections: ["videos"],
    profileSorting: "latest",
    excludePinnedPosts: true,
    shouldDownloadVideos: false,
    shouldDownloadCovers: false,
  }),
});
if (!runRes.ok) {
  console.error(
    `apify start failed: ${runRes.status} ${runRes.statusText}`,
  );
  process.exit(1);
}
const runJson = (await runRes.json()) as {
  data?: { id?: string; defaultDatasetId?: string; status?: string };
};
const runData = runJson.data;
if (
  !runData?.id ||
  !runData.defaultDatasetId ||
  runData.status !== "SUCCEEDED"
) {
  console.error("apify run did not succeed:", runData);
  process.exit(1);
}
console.log(
  `apify run ${runData.id} SUCCEEDED, dataset ${runData.defaultDatasetId}`,
);

// 2. Post a synthetic webhook with the real run/dataset ids.
const webhookRes = await fetch(endpoint, {
  method: "POST",
  headers: {
    "Content-Type": "application/json",
    Authorization: `Bearer ${SUPABASE_ANON_KEY}`,
    apikey: SUPABASE_ANON_KEY,
    "X-Apify-Webhook-Secret": APIFY_WEBHOOK_SECRET,
  },
  body: JSON.stringify({
    eventType: "ACTOR.RUN.SUCCEEDED",
    resource: {
      id: runData.id,
      defaultDatasetId: runData.defaultDatasetId,
      status: "SUCCEEDED",
      actId: "clockworks~tiktok-scraper",
    },
    social_link_id: SEED_TIKTOK_SOCIAL_LINK_ID,
    scrape_mode: "tiktok_profile",
    run_id: runData.id,
    apify_finished_at: new Date().toISOString(),
  }),
});
const webhookBody = await webhookRes.json();
console.log("webhook response:", webhookRes.status, webhookBody);
if (
  webhookRes.status !== 200 ||
  webhookBody.inserted !== true ||
  webhookBody.duplicate !== false
) {
  console.error("webhook did not insert successfully");
  process.exit(1);
}

// 3. Read back via service role to verify row + denorm.
const supabase = createClient(SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY, {
  auth: { persistSession: false, autoRefreshToken: false },
});

const { data: snap, error: snapErr } = await supabase
  .from("metric_snapshots")
  .select(
    "id,status,follower_count,following_count,total_likes,video_count,avg_views_last_10,is_verified,is_latest,apify_run_id,fetched_at",
  )
  .eq("apify_run_id", runData.id)
  .maybeSingle();
if (snapErr || !snap) {
  console.error("metric_snapshots row missing:", snapErr);
  process.exit(1);
}
console.log("snapshot row:", snap);
if (
  snap.status !== "fresh" ||
  snap.is_latest !== true ||
  typeof snap.follower_count !== "number" ||
  snap.follower_count <= 0
) {
  console.error("snapshot did not land as fresh with positive follower_count");
  process.exit(1);
}

const { data: profile, error: profileErr } = await supabase
  .from("creator_profiles")
