//   2. POST a synthetic webhook carrying the real run_id + defaultDatasetId
//   3. Assert the webhook returned 200 inserted:true duplicate:false
//
// The DB-side assertions (metric_snapshots row written, creator_profiles
// denorm trigger fired) are done separately via Supabase MCP execute_sql
// after this script completes — see progress.txt entry for US-016.

const {
  APIFY_KEY,
  APIFY_WEBHOOK_SECRET,
  SUPABASE_URL,
  SUPABASE_ANON_KEY,
} = process.env;

if (!APIFY_KEY || !APIFY_WEBHOOK_SECRET || !SUPABASE_URL || !SUPABASE_ANON_KEY) {
  console.error(
    "APIFY_KEY, APIFY_WEBHOOK_SECRET, SUPABASE_URL, SUPABASE_ANON_KEY required in .env",
  );
  process.exit(1);
}

const SEED_TIKTOK_SOCIAL_LINK_ID = "11111111-1111-1111-1111-111111111020";
const TIKTOK_HANDLE = "tiktok"; // cheap + stable public account
const endpoint = `${SUPABASE_URL}/functions/v1/apify-webhook`;

console.log(`kicking Apify tiktok_profile for @${TIKTOK_HANDLE}...`);
const runUrl = new URL(
  "https://api.apify.com/v2/acts/clockworks~tiktok-scraper/runs",
);
runUrl.searchParams.set("token", APIFY_KEY);
runUrl.searchParams.set("waitForFinish", "90");

const runRes = await fetch(runUrl.toString(), {
  method: "POST",
  headers: { "content-type": "application/json" },
  body: JSON.stringify({
    profiles: [TIKTOK_HANDLE],
    resultsPerPage: 10,
    profileScrapeSections: ["videos"],
    profileSorting: "latest",
    excludePinnedPosts: true,
    shouldDownloadVideos: false,
    shouldDownloadCovers: false,
  }),
});
if (!runRes.ok) {
  console.error(`apify start failed: ${runRes.status} ${runRes.statusText}`);
  process.exit(1);
}
const runJson = (await runRes.json()) as {
  data?: { id?: string; defaultDatasetId?: string; status?: string };
};
const runData = runJson.data;
if (
  !runData?.id ||
  !runData.defaultDatasetId ||
  runData.status !== "SUCCEEDED"
) {
  console.error("apify run did not succeed:", runData);
  process.exit(1);
}
console.log(
  `apify run ${runData.id} ${runData.status}, dataset ${runData.defaultDatasetId}`,
);

const webhookRes = await fetch(endpoint, {
  method: "POST",
  headers: {
    "Content-Type": "application/json",
    Authorization: `Bearer ${SUPABASE_ANON_KEY}`,
    apikey: SUPABASE_ANON_KEY,
    "X-Apify-Webhook-Secret": APIFY_WEBHOOK_SECRET,
  },
  body: JSON.stringify({
    eventType: "ACTOR.RUN.SUCCEEDED",
    resource: {
      id: runData.id,
      defaultDatasetId: runData.defaultDatasetId,
      status: "SUCCEEDED",
      actId: "clockworks~tiktok-scraper",
    },
    social_link_id: SEED_TIKTOK_SOCIAL_LINK_ID,
    scrape_mode: "tiktok_profile",
    run_id: runData.id,
    apify_finished_at: new Date().toISOString(),
  }),
});
const webhookBody = await webhookRes.json();
console.log("webhook response:", webhookRes.status, webhookBody);
if (
  webhookRes.status !== 200 ||
  webhookBody.inserted !== true ||
  webhookBody.duplicate !== false
) {
  console.error("webhook did not insert successfully");
  process.exit(1);
}

console.log(
  `ok — live e2e completed. run_id=${runData.id} — verify snapshot + denorm via MCP execute_sql.`,
);

// Smoke test for the deployed apify-webhook edge function (US-016).
//
// Usage: bun run scripts/test/apify-webhook.ts
// Requires SUPABASE_URL, SUPABASE_ANON_KEY, APIFY_WEBHOOK_SECRET in .env.
//
// Covers the paths that don't need a live Apify run — the SUCCEEDED branch
// (which pulls a real dataset) is exercised end-to-end in the iteration's
// MCP verification, not here.
//
// Asserts:
//   1. Missing X-Apify-Webhook-Secret → 401 UNAUTHORIZED
//   2. Wrong secret → 401 UNAUTHORIZED (constant-time reject)
//   3. Malformed JSON body with valid secret → 400 INVALID_JSON
//   4. Missing required fields → 400 INVALID_REQUEST
//   5. scrape_mode='ig_details' → 200 { skipped:'unsupported_scrape_mode' }
//   6. tiktok_profile + ACTOR.RUN.FAILED → 200 { inserted:true, duplicate:false }
//   7. Replay same run_id → 200 { inserted:false, duplicate:true }

const supabaseUrl = process.env.SUPABASE_URL;
const anonKey = process.env.SUPABASE_ANON_KEY;
const webhookSecret = process.env.APIFY_WEBHOOK_SECRET;
if (!supabaseUrl || !anonKey || !webhookSecret) {
  console.error(
    "SUPABASE_URL, SUPABASE_ANON_KEY, and APIFY_WEBHOOK_SECRET are required in .env",
  );
  process.exit(1);
}

const endpoint = `${supabaseUrl}/functions/v1/apify-webhook`;
// anon key is required by the Supabase gateway even for verify_jwt=false
// functions; the edge function itself validates X-Apify-Webhook-Secret.
const gatewayHeaders = {
  Authorization: `Bearer ${anonKey}`,
  apikey: anonKey,
};

const SEED_TIKTOK_SOCIAL_LINK_ID = "11111111-1111-1111-1111-111111111020";
const unique = Date.now();

function basePayload(overrides: Record<string, unknown> = {}) {
  const runId = `us016_test_${unique}_${Math.random().toString(36).slice(2, 10)}`;
  return {
    eventType: "ACTOR.RUN.FAILED",
    resource: {
      id: runId,
      defaultDatasetId: `dataset_${runId}`,
      status: "FAILED",
      actId: "clockworks~tiktok-scraper",
    },
    social_link_id: SEED_TIKTOK_SOCIAL_LINK_ID,
    scrape_mode: "tiktok_profile",
    run_id: runId,
    apify_finished_at: new Date().toISOString(),
    ...overrides,
  };
}

async function postRaw(
  body: string | object,
  extraHeaders: Record<string, string> = {},
) {
  const res = await fetch(endpoint, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      ...gatewayHeaders,
      ...extraHeaders,
    },
    body: typeof body === "string" ? body : JSON.stringify(body),
  });
  const data = await res.json().catch(() => null);
  return { status: res.status, data };
}

function expect(label: string, cond: boolean, ctx: unknown) {
  if (!cond) {
    console.error(`FAIL ${label}:`, ctx);
    process.exit(1);
  }
  console.log(`ok — ${label}`);
}

// 1. Missing secret header
{
  const r = await postRaw(basePayload());
  expect(
    "missing secret → 401 UNAUTHORIZED",
    r.status === 401 && r.data?.error === "UNAUTHORIZED",
    r,
  );
}

// 2. Wrong secret header
{
  const r = await postRaw(basePayload(), {
    "X-Apify-Webhook-Secret": "definitely-not-the-real-secret",
  });
  expect(
    "wrong secret → 401 UNAUTHORIZED",
    r.status === 401 && r.data?.error === "UNAUTHORIZED",
    r,
  );
}

// 3. Malformed JSON (valid secret)
{
  const r = await postRaw("{not json", {
    "X-Apify-Webhook-Secret": webhookSecret,
  });
  expect(
    "malformed json → 400 INVALID_JSON",
    r.status === 400 && r.data?.error === "INVALID_JSON",
    r,
  );
}

// 4. Missing required fields
{
  const r = await postRaw(
    { eventType: "ACTOR.RUN.SUCCEEDED" },
    { "X-Apify-Webhook-Secret": webhookSecret },
  );
  expect(
    "missing fields → 400 INVALID_REQUEST",
    r.status === 400 && r.data?.error === "INVALID_REQUEST",
    r,
  );
}

// 5. ig_details scrape_mode → unsupported_scrape_mode
{
  const r = await postRaw(
    basePayload({ scrape_mode: "ig_details" }),
    { "X-Apify-Webhook-Secret": webhookSecret },
  );
  expect(
    "ig_details → 200 skipped",
    r.status === 200 && r.data?.skipped === "unsupported_scrape_mode",
    r,
  );
}

// 6. tiktok_profile + FAILED event → inserts failed snapshot
const failedRunBody = basePayload();
{
  const r = await postRaw(failedRunBody, {
    "X-Apify-Webhook-Secret": webhookSecret,
  });
  expect(
    "tiktok_profile FAILED → 200 inserted",
    r.status === 200 && r.data?.inserted === true && r.data?.duplicate === false,
    r,
  );
}

// 7. Same run_id replay → idempotent duplicate
{
  const r = await postRaw(failedRunBody, {
    "X-Apify-Webhook-Secret": webhookSecret,
  });
  expect(
    "replay same run_id → 200 duplicate",
    r.status === 200 && r.data?.inserted === false && r.data?.duplicate === true,
    r,
  );
}

console.log("all apify-webhook smoke tests passed");

